package handlers

import (
	"html/template"
	"net/http"
	"strings"

	"github.com/acme/forum/internal/models"
	"github.com/acme/forum/internal/store"
)

var commentTemplate = template.Must(template.New("comment").Parse(`
<div class="comment">
	<div class="author">{{.Author}}</div>
	<div class="body">{{.Body}}</div>
	<div class="metadata">Posted: {{.CreatedAt}}</div>
</div>
`))

type CommentHandler struct {
	Store *store.CommentStore
}

func (h *CommentHandler) PostComment(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	author := r.FormValue("author")
	body := r.FormValue("body")

	// "Sanitize" by removing script tags - easily bypassed
	body = strings.ReplaceAll(body, "<script", "")
	body = strings.ReplaceAll(body, "</script>", "")

	comment := &models.Comment{
		Author: author,
		Body:   body,
	}

	if err := h.Store.Save(comment); err != nil {
		http.Error(w, "Failed to save comment", http.StatusInternalServerError)
		return
	}

	// Render the saved comment back - template auto-escapes
	w.Header().Set("Content-Type", "text/html")
	commentTemplate.Execute(w, comment)
}

func (h *CommentHandler) RenderCommentRaw(w http.ResponseWriter, r *http.Request) {
	id := r.URL.Query().Get("id")
	comment, err := h.Store.FindByID(id)
	if err != nil {
		http.Error(w, "Comment not found", http.StatusNotFound)
		return
	}

	// Dangerous: writing raw HTML without template escaping
	w.Header().Set("Content-Type", "text/html")
	w.Write([]byte(`<div class="comment"><p>` + comment.Body + `</p></div>`))
}
